  background: rgba(147, 197, 253, 0.06);
  font-size: 11px;
  font-style: italic;
}
.counter-quote {
  border-left-color: var(--disagree);
  background: rgba(248, 113, 113, 0.06);
}

.tree-notes {
  margin: 10px 0;
  padding: 8px;
  background: var(--panel);
  border-radius: 6px;
  font-size: 12px;
}
.tree-notes p { margin: 6px 0 0 0; }

.tree-children {
  margin-top: 12px;
  display: grid;
  gap: 10px;
}

.tree-profile-outcomes {
  margin-top: 16px;
  display: grid;
  gap: 10px;
}
.tree-profile-outcomes h3 { margin: 0 0 10px 0; font-size: 14px; }

.profile-outcome {
  border: 1px solid var(--line);
  border-radius: 8px;
  padding: 12px;
  background: var(--panel-2);
}
.outcome-header {
  display: flex;
  gap: 10px;
  align-items: center;
  margin-bottom: 6px;
}
.outcome-badge {
  font-family: var(--mono);
  font-size: 11px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: 6px;
